const mensajes = $input.all().map(item => item.json.mensaje);


const texto_completo = mensajes.join("\n\n");


return [{ json: { texto_agrupado: texto_completo } }];

// Divide la respuesta del agente en mensajes cortos para WhatsApp
const output = $input.first().json.output || '';

// Limpiar la respuesta
const cleaned = output.trim();

// Dividir por doble salto de línea (párrafos)
const chunks = cleaned
  .split(/\n{2,}/)
  .map(c => c.trim())
  .filter(c => c.length > 2);

// Si no hay división, devolver el mensaje completo
if (chunks.length === 0) {
  return [{ json: { message: cleaned } }];
}

// Devolver cada párrafo como mensaje separado
return chunks.map(chunk => ({ json: { message: chunk } }));

